```

- [ ] **Step 2: Write the failing unit tests**

Create `src/unit-tests/csrf.guard.unit-spec.ts`:

```typescript
import { ExecutionContext, ForbiddenException } from '@nestjs/common';

import { CsrfGuard } from '@modules/auth/guards/csrf.guard';

const makeContext = ({
	csrfHeader,
	csrfCookie,
}: {
	csrfHeader?: string;
	csrfCookie?: string;
}): ExecutionContext =>
	({
		switchToHttp: () => ({
			getRequest: () => ({
				headers: { 'x-csrf-token': csrfHeader },
				cookies: { csrf_token: csrfCookie },
			}),
		}),
	}) as unknown as ExecutionContext;

describe('CsrfGuard', () => {
	let guard: CsrfGuard;

	beforeEach(() => {
		guard = new CsrfGuard();
	});

	it('should return true when header matches cookie', () => {
		const ctx = makeContext({ csrfHeader: 'abc123', csrfCookie: 'abc123' });
		expect(guard.canActivate(ctx)).toBe(true);
	});

	it('should throw ForbiddenException when header is missing', () => {
		const ctx = makeContext({ csrfHeader: undefined, csrfCookie: 'abc123' });
		expect(() => guard.canActivate(ctx)).toThrow(ForbiddenException);
	});

	it('should throw ForbiddenException when cookie is missing', () => {
		const ctx = makeContext({ csrfHeader: 'abc123', csrfCookie: undefined });
		expect(() => guard.canActivate(ctx)).toThrow(ForbiddenException);
	});

	it('should throw ForbiddenException when header and cookie do not match', () => {
		const ctx = makeContext({ csrfHeader: 'abc123', csrfCookie: 'xyz789' });
		expect(() => guard.canActivate(ctx)).toThrow(ForbiddenException);
	});
});
```

- [ ] **Step 3: Run tests — expect failures**

```bash
npm run test:unit -- --testPathPattern="csrf.guard"
```

Expected: 3 failures (guard stub always returns false, no ForbiddenException thrown).

---

## Task 3: CsrfGuard — implement

**Files:**
- Modify: `src/modules/auth/guards/csrf.guard.ts`

- [ ] **Step 1: Implement the guard**

Replace `src/modules/auth/guards/csrf.guard.ts` with:

```typescript
import { CanActivate, ExecutionContext, ForbiddenException, Injectable } from '@nestjs/common';

import type { FastifyRequest } from 'fastify';

@Injectable()
export class CsrfGuard implements CanActivate {
	canActivate(context: ExecutionContext): boolean {
		const request = context.switchToHttp().getRequest<FastifyRequest>();
		const headerToken = request.headers['x-csrf-token'] as string | undefined;
		const cookieToken = (request.cookies as Record<string, string | undefined>)['csrf_token'];

		if (!headerToken || !cookieToken || headerToken !== cookieToken) {
			throw new ForbiddenException('Invalid CSRF token');
		}

		return true;
	}
}
```

- [ ] **Step 2: Run tests — expect all pass**

```bash
npm run test:unit -- --testPathPattern="csrf.guard"
```

Expected: 4 passing.

- [ ] **Step 3: Commit**

```bash
