git commit -m "feat: add CsrfGuard with unit tests"
```

---

## Task 4: Controller — set, rotate, and clear CSRF cookie

**Files:**
- Modify: `src/modules/auth/auth.controller.ts`

Context: `exchangeToken` sets the refresh token cookie. `refresh` rotates it. `logout` and `logoutAll` currently return `{ success: true }` but do NOT inject `@Res()` or clear any cookies — we add that here.

The refresh token cookie is also changed from `sameSite: 'strict'` to `sameSite: 'none'` so cross-origin SPAs can send it. CSRF protection compensates for this.

- [ ] **Step 1: Add imports**

At the top of `src/modules/auth/auth.controller.ts`, add `CSRF_TOKEN_COOKIE_NAME` to the auth constants import and add `randomBytes` from crypto:

```typescript
import { randomBytes } from 'node:crypto';
```

```typescript
import { CSRF_TOKEN_COOKIE_NAME, REFRESH_TOKEN_COOKIE_NAME } from '@modules/auth/constants/auth.constant';
```

Also add `CsrfGuard` and `UseGuards` imports:

```typescript
import { UseGuards } from '@nestjs/common';
import { CsrfGuard } from '@modules/auth/guards/csrf.guard';
```

- [ ] **Step 2: Add a private helper method to the controller class**

Add this private method inside the `AuthController` class (above `githubAuth`):

```typescript
private setCsrfCookie({ reply }: { reply: FastifyReply }): void {
	const token = randomBytes(32).toString('hex');
	reply.setCookie(CSRF_TOKEN_COOKIE_NAME, token, {
		httpOnly: false,
		secure: !isDevEnv(),
		sameSite: isDevEnv() ? 'lax' : 'none',
		path: '/',
		maxAge: 30 * 24 * 60 * 60,
	});
}

private clearAuthCookies({ reply }: { reply: FastifyReply }): void {
	reply.clearCookie(REFRESH_TOKEN_COOKIE_NAME, { path: '/api/auth' });
	reply.clearCookie(CSRF_TOKEN_COOKIE_NAME, { path: '/' });
}
```

- [ ] **Step 3: Update `exchangeToken` — set CSRF cookie and update refresh cookie sameSite**

Replace the `exchangeToken` method body:

```typescript
async exchangeToken(
	@Body() dto: TokenExchangeDto,
	@Req() request: FastifyRequest,
	@Res() reply: FastifyReply,
): Promise<void> {
	const result = await this.authService.exchangeCode({
		code: dto.code,
		ip: request.ip,
		userAgent: request.headers['user-agent'] ?? '',
		provider: 'github',
	});

	reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
		httpOnly: true,
		secure: !isDevEnv(),
		sameSite: isDevEnv() ? 'lax' : 'none',
		path: '/api/auth',
		maxAge: 30 * 24 * 60 * 60,
	});

	this.setCsrfCookie({ reply });

	reply.send({ access_token: result.accessToken });
}
```

- [ ] **Step 4: Update `refresh` — add CsrfGuard and rotate CSRF cookie**

Replace the `refresh` method and its decorators:

```typescript
@Public()
@UseGuards(CsrfGuard)
@Throttle({ default: { limit: 5, ttl: 60000 } })
@Post('refresh')
@ApiOperation({ summary: 'Refresh access token using refresh token cookie' })
@ApiResponse({
	status: HttpStatus.OK,
	description: 'Returns new access token, rotates refresh cookie',
})
@ApiResponse({
	status: HttpStatus.UNAUTHORIZED,
	description: 'No or invalid refresh token',
})
@ApiResponse({
	status: HttpStatus.FORBIDDEN,
	description: 'Invalid CSRF token',
})
@LogExecution({ logParams: false, logResponse: false })
async refresh(
	@Req() request: FastifyRequest,
	@Res() reply: FastifyReply,
): Promise<void> {
	const refreshToken = (request.cookies as Record<string, string>)[REFRESH_TOKEN_COOKIE_NAME];
	if (!refreshToken) throw new UnauthorizedException('No refresh token');

	const result = await this.authService.refreshTokens({ refreshToken });

	reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
		httpOnly: true,
		secure: !isDevEnv(),
		sameSite: isDevEnv() ? 'lax' : 'none',
		path: '/api/auth',
		maxAge: 30 * 24 * 60 * 60,
	});

	this.setCsrfCookie({ reply });

	reply.send({ access_token: result.accessToken });
}
```

- [ ] **Step 5: Update `logout` — inject @Res() and clear cookies**

Replace the `logout` method:

```typescript
@Post('logout')
@ApiOperation({ summary: 'Log out current session' })
@ApiResponse({ status: HttpStatus.OK, description: 'Successfully logged out' })
@LogExecution()
async logout(
	@CurrentUser() user: IRequestUser,
	@Res() reply: FastifyReply,
): Promise<void> {
	await this.authService.logout({
		userId: user.user_id,
		sessionId: user.session_id,
	});
	this.clearAuthCookies({ reply });
	reply.send({ success: true });
}
```

- [ ] **Step 6: Update `logoutAll` — inject @Res() and clear cookies**

Replace the `logoutAll` method:

```typescript
@Post('logout/all')
@ApiOperation({ summary: 'Log out all sessions for current user' })
@ApiResponse({ status: HttpStatus.OK, description: 'All sessions terminated' })
@LogExecution()
async logoutAll(
	@CurrentUser() user: IRequestUser,
	@Res() reply: FastifyReply,
): Promise<void> {
	await this.authService.logoutAll({ userId: user.user_id });
	this.clearAuthCookies({ reply });
	reply.send({ success: true });
}
```

- [ ] **Step 7: Commit**

```bash
git add src/modules/auth/auth.controller.ts
git commit -m "feat: set/rotate/clear CSRF cookie in auth controller"
```

---

## Task 5: CORS — allow x-csrf-token header

**Files:**
- Modify: `src/main.ts`

- [ ] **Step 1: Update CORS config**

In `src/main.ts`, replace:

```typescript
