	await request(httpServer)
		.post('/api/auth/refresh')
		.set('Cookie', `refresh_token=${refreshToken}; csrf_token=sometoken`)
		.expect(403);
});

it('should return 403 when x-csrf-token header does not match cookie', async () => {
	const user = createTestUser({ email: `csrf-mismatch-${randomUUID()}@example.com` });
	await insertUser({ knex, user });

	const sessionId = randomUUID();
	const refreshToken = randomUUID();
	const now = new Date().toISOString();

	await sessionService.createSession({
		session: {
			user_id: user._id,
			session_id: sessionId,
			role: null,
			company_id: null,
			provider: 'github',
			ip: '127.0.0.1',
			user_agent: 'test',
			created_at: now,
			last_active: now,
		},
		refreshToken,
	});

	await request(httpServer)
		.post('/api/auth/refresh')
		.set('Cookie', `refresh_token=${refreshToken}; csrf_token=token-a`)
		.set('x-csrf-token', 'token-b')
		.expect(403);
});

it('should succeed and rotate csrf_token cookie when x-csrf-token matches cookie', async () => {
	const user = createTestUser({ email: `csrf-ok-${randomUUID()}@example.com` });
	await insertUser({ knex, user });

	const sessionId = randomUUID();
	const refreshToken = randomUUID();
	const csrfToken = randomUUID();
	const now = new Date().toISOString();

	await sessionService.createSession({
		session: {
			user_id: user._id,
			session_id: sessionId,
			role: null,
			company_id: null,
			provider: 'github',
			ip: '127.0.0.1',
			user_agent: 'test',
			created_at: now,
			last_active: now,
		},
		refreshToken,
	});

	const response = await request(httpServer)
		.post('/api/auth/refresh')
		.set('Cookie', `refresh_token=${refreshToken}; csrf_token=${csrfToken}`)
		.set('x-csrf-token', csrfToken)
		.expect(200);

	expect(response.body).toHaveProperty('access_token');
	const newCsrf = extractCsrfToken(response as unknown as Response);
	expect(newCsrf).toBeTruthy();
	expect(newCsrf).not.toBe(csrfToken);
});
```

