1	import { Inject, Injectable, Logger } from '@nestjs/common';
2	import { Redis } from 'ioredis';
3	import Keyv from 'keyv';
4	import Redlock, { Lock } from 'redlock';
5	
6	import {
7		CACHE_READ_MANAGER,
8		CACHE_WRITE_MANAGER,
9		REDIS_READ_CLIENT,
10		REDIS_WRITE_CLIENT,
11	} from '@modules/cache/cache.constant';
12	import {
13		CacheError,
14		ConsistencyLevel,
15		Namespaces,
16	} from '@modules/cache/types/cache.interface';
17	
18	export { ConsistencyLevel, CacheError } from '@modules/cache/types/cache.interface';
19	
20	@Injectable()
21	export class CacheService {
22		private readonly logger = new Logger(CacheService.name);
23		private readonly redlock: Redlock;
24		private readonly redisWriteClient: Redis;
25		private readonly redisReadClient: Redis;
26		private readonly cacheWriteManager: Keyv;
27		private readonly cacheReadManager: Keyv;
28		private readonly recentWrites = new Map<string, number>();
29		private readonly CONSISTENCY_WINDOW_MS = 1000;
30		private isReadReplicaHealthy = true;
31	
32		constructor(
33			@Inject(CACHE_WRITE_MANAGER) cacheWriteManager: Keyv,
34			@Inject(CACHE_READ_MANAGER) cacheReadManager: Keyv,
35			@Inject(REDIS_WRITE_CLIENT) redisWriteClient: Redis,
36			@Inject(REDIS_READ_CLIENT) redisReadClient: Redis,
37		) {
38			this.cacheWriteManager = cacheWriteManager;
39			this.cacheReadManager = cacheReadManager;
40			this.redisWriteClient = redisWriteClient;
41			this.redisReadClient = redisReadClient;
42			this.redlock = new Redlock([redisWriteClient], {
43				driftFactor: 0.01,
44				retryCount: 10,
45				retryDelay: 200,
46				retryJitter: 200,
47			});
48	
49			this.setupHealthChecks();
50			this.startRecentWritesCleanup();
51		}
52	
53		async get<T>({
54			namespace,
55			key,
56			consistencyLevel = ConsistencyLevel.EVENTUAL,
57		}: {
58			namespace: Namespaces;
59			key: string;
60			consistencyLevel?: ConsistencyLevel;
61		}): Promise<T | null> {
62			const namespacedKey = this.getNamespacedKey({ namespace, key });
63	
64			const readFromMaster = this.shouldReadFromMaster({
65				namespace,
66				key: namespacedKey,
67				consistencyLevel,
68			});
69			const cacheManager = readFromMaster ? this.cacheWriteManager : this.cacheReadManager;
70			const source = readFromMaster ? 'master' : 'replica';
71	
72			try {
73				const result = (await cacheManager.get(namespacedKey)) as T;
74	
75				if (!result) {
76					this.logger.log('Cache miss', { namespace, key, consistencyLevel, source });
77					return null;
78				}
79	
80				this.logger.log('Cache hit', { namespace, key });
81	
82				return result;
83			} catch (error) {
84				const e = error as Error;
85				this.logger.error(`Error retrieving from cache: ${e.message}`, e.stack, { source });
86	
87				if (!readFromMaster && this.isReadReplicaHealthy) {
88					this.logger.warn('Read replica failed, falling back to master', {
89						namespace,
90						key,
91					});
92					this.isReadReplicaHealthy = false;
93					return this.get({ namespace, key, consistencyLevel: ConsistencyLevel.STRONG });
94				}
95	
96				throw this.createCacheError({ code: 'CONNECTION_FAILED', originalError: e });
97			}
98		}
99	
100		async set({
101			namespace,
102			key,
103			value,
104			ttl,
105		}: {
106			namespace: Namespaces;
107			key: string;
108			value: unknown;
109			ttl?: number;
110		}): Promise<void> {
111			const namespacedKey = this.getNamespacedKey({ namespace, key });
112	
113			try {
114				await this.cacheWriteManager.set(namespacedKey, value, ttl);
115				this.trackRecentWrite({ key: namespacedKey });
116				this.logger.log('Cached value', { namespace, key, ttl });
117			} catch (error) {
118				const e = error as Error;
119				this.logger.error(`Error setting cache: ${e.message}`, e.stack);
120				throw this.createCacheError({ code: 'OPERATION_FAILED', originalError: e });
121			}
122		}
123	
124		async has({
125			namespace,
126			key,
127		}: {
128			namespace: Namespaces;
129			key: string;
130		}): Promise<boolean> {
131			this.logger.log('Checking cache key existence', { namespace, key });
132			const value = await this.get<unknown>({ namespace, key });
133			return value !== null;
134		}
135	
136		async deleteOne({
137			namespace,
138			key,
139		}: {
140			namespace: Namespaces;
141			key: string;
142		}): Promise<boolean> {
143			try {
144				const namespacedKey = this.getNamespacedKey({ namespace, key });
145				await this.cacheWriteManager.delete(namespacedKey);
146				this.logger.log('Deleted cache key', { namespace, key });
147				return true;
148			} catch (error) {
149				const e = error as Error;
150				this.logger.error(`Error deleting from cache: ${e.message}`, e.stack);
151				return false;
152			}
153		}
154	
155		async deleteAll({ namespace }: { namespace: Namespaces }): Promise<boolean> {
156			try {
157				await this.cacheWriteManager.clear();
158	
159				await new Promise((resolve) => setTimeout(resolve, 100));
160	
161				await this.cacheReadManager.clear();
162				this.recentWrites.clear();
163				this.logger.log('Cleared all cache', { namespace });
164				return true;
165			} catch (error) {
166				const e = error as Error;
167				this.logger.error(`Error clearing cache: ${e.message}`, e.stack);
168				return false;
169			}
170		}
171	
172		async incrementByOne({
173			namespace,
174			key,
175		}: {
176			namespace: Namespaces;
177			key: string;
178		}): Promise<void> {
179			try {
180				const namespacedKey = this.getNamespacedKey({ namespace, key });
181				await this.redisWriteClient.incr(namespacedKey);
182			} catch (error) {
183				const e = error as Error;
184				this.logger.error(`Error incrementing cache key: ${e.message}`, e.stack, {
185					namespace,
186					key,
187				});
188				throw error;
189			}
190		}
191	
192		async withLock<T>({
193			lockKey,
194			operation,
195			ttl = 5000,
196		}: {
197			lockKey: string;
198			operation: () => Promise<T>;
199			ttl?: number;
200		}): Promise<T> {
201			this.logger.log('Acquiring lock', { lockKey, ttlMs: ttl });
202			const lock = await this.redlock.acquire([lockKey], ttl);
203	
204			try {
205				return await operation();
206			} finally {
207				this.logger.log('Releasing lock', { lockKey });
208				await lock.release();
209			}
210		}
211	
212		async acquireLock({ lockKey, ttl }: { lockKey: string; ttl: number }): Promise<Lock> {
213			try {
214				this.logger.log('Acquiring lock', { lockKey, ttlMs: ttl });
215				return await this.redlock.acquire([lockKey], ttl);
216			} catch (error) {
217				this.logger.error(`Failed to acquire lock: ${error}`);
218				throw error;
219			}
220		}
221	
222		async releaseLock({ lock }: { lock: Lock }): Promise<void> {
223			try {
224				this.logger.log('Releasing lock', { lockKey: lock.resources.join(',') });
225				await lock.release();
226			} catch (error) {
227				this.logger.error(`Failed to release lock: ${error}`);
228				throw error;
229			}
230		}
231	
232		private getNamespacedKey({
233			namespace,
234			key,
235		}: {
236			namespace: Namespaces;
237			key: string;
238		}): string {
239			return `${namespace}:${key}`;
240		}
241	
242		private shouldReadFromMaster({
243			key,
244			consistencyLevel,
245		}: {
246			namespace: Namespaces;
247			key: string;
248			consistencyLevel: ConsistencyLevel;
249		}): boolean {
250			if (consistencyLevel === ConsistencyLevel.STRONG) {
251				return true;
252			}
253	
254			if (!this.isReadReplicaHealthy) {
255				return true;
256			}
257	
258			const lastWriteTime = this.recentWrites.get(key);
259			if (lastWriteTime) {
260				const timeSinceWrite = Date.now() - lastWriteTime;
261				return timeSinceWrite < this.CONSISTENCY_WINDOW_MS;
262			}
263	
264			return false;
265		}
266	
267		private trackRecentWrite({ key }: { key: string }): void {
268			this.recentWrites.set(key, Date.now());
269		}
270	
271		private startRecentWritesCleanup(): void {
272			setInterval(() => {
273				const now = Date.now();
274				for (const [key, timestamp] of this.recentWrites.entries()) {
275					if (now - timestamp > this.CONSISTENCY_WINDOW_MS * 2) {
276						this.recentWrites.delete(key);
277					}
278				}
279			}, this.CONSISTENCY_WINDOW_MS).unref();
280		}
281	
282		private setupHealthChecks(): void {
283			this.redisReadClient.on('error', (error) => {
284				this.logger.error('Read replica connection error:', error);
285				this.isReadReplicaHealthy = false;
286			});
287	
288			this.redisReadClient.on('ready', () => {
289				this.logger.log('Read replica connection restored');
290				this.isReadReplicaHealthy = true;
291			});
292	
293			this.redisWriteClient.on('error', (error) => {
294				this.logger.error('Write client connection error:', error);
295			});
296		}
297	
298		private createCacheError({
299			code,
300			originalError,
301		}: {
302			code: CacheError['code'];
303			originalError?: Error;
304		}): CacheError {
305			const error = new Error(`Cache operation failed: ${code}`) as CacheError;
306			error.code = code;
307			if (originalError) {
308				error.originalError = originalError;
309			}
310			return error;
311		}
312	}
