import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';

describe('DbModule (e2e)', () => {
	let app: INestApplication;
	let moduleFixture: TestingModule;
	let knexWrite: Knex;
	let knexRead: Knex;

	beforeAll(async () => {
		moduleFixture = await Test.createTestingModule({
			imports: [AppModule],
		}).compile();

		app = moduleFixture.createNestApplication();
		await app.init();

		knexWrite = moduleFixture.get<Knex>(KNEX_WRITE_CONNECTION);
		knexRead = moduleFixture.get<Knex>(KNEX_READ_CONNECTION);
	});

	afterAll(async () => {
		await app.close();
	});

	describe('write connection', () => {
		it('should be defined', () => {
			expect(knexWrite).toBeDefined();
		});

		it('should execute a raw query', async () => {
			const result = await knexWrite.raw('SELECT 1 AS value');
			expect(result.rows[0].value).toBe(1);
		});

		it('should have pool configuration', () => {
			const config = knexWrite.client.config;
			expect(config.pool.min).toBe(2);
			expect(config.pool.max).toBe(10);
		});
	});

	describe('read connection', () => {
		it('should be defined', () => {
			expect(knexRead).toBeDefined();
		});

		it('should execute a raw query', async () => {
			const result = await knexRead.raw('SELECT 1 AS value');
			expect(result.rows[0].value).toBe(1);
		});

		it('should have pool configuration', () => {
			const config = knexRead.client.config;
			expect(config.pool.min).toBe(2);
			expect(config.pool.max).toBe(10);
		});
	});

	describe('migrations', () => {
		it('should be able to run migrations', async () => {
			await expect(
				knexWrite.migrate.latest({ directory: './src/migrations' }),
			).resolves.not.toThrow();
		});

		it('should have all expected tables after migration', async () => {
			const tables = await knexWrite
				.select('tablename')
				.from('pg_tables')
				.where({ schemaname: 'public' })
				.whereNotIn('tablename', ['knex_migrations', 'knex_migrations_lock']);

			const tableNames = tables.map((t: { tablename: string }) => t.tablename);

			expect(tableNames).toEqual(
				expect.arrayContaining(['users', 'companies', 'company_members', 'oauth_accounts', 'invitations']),
			);
		});
	});
});

