import { randomUUID } from 'crypto';

import { INestApplication } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';
import { Redis } from 'ioredis';

import { AppModule } from '@modules/app/app.module';
import { REDIS_WRITE_CLIENT } from '@modules/cache/cache.constant';
import { CacheService, ConsistencyLevel } from '@modules/cache/cache.service';
import { Namespaces } from '@modules/cache/types/cache.interface';

describe('CacheModule (e2e)', () => {
	let app: INestApplication;
	let moduleFixture: TestingModule;
	let cacheService: CacheService;
	let redis: Redis;

	beforeAll(async () => {
		moduleFixture = await Test.createTestingModule({
			imports: [AppModule],
		}).compile();

		app = moduleFixture.createNestApplication();
		await app.init();

		cacheService = moduleFixture.get<CacheService>(CacheService);
		redis = moduleFixture.get<Redis>(REDIS_WRITE_CLIENT);
	});

	afterAll(async () => {
		await redis.flushdb();
		await app.close();
	});

	afterEach(async () => {
		await redis.flushdb();
	});

	describe('set and get', () => {
		it('should store and retrieve a string value', async () => {
			const key = randomUUID();
			const value = 'test-value';

			await cacheService.set({ namespace: Namespaces.AUTH_CODE, key, value });
			const result = await cacheService.get<string>({ namespace: Namespaces.AUTH_CODE, key });

			expect(result).toBe(value);
		});

		it('should store and retrieve an object value', async () => {
			const key = randomUUID();
			const value = { userId: randomUUID(), role: 'admin' };

			await cacheService.set({ namespace: Namespaces.SESSION, key, value });
			const result = await cacheService.get<typeof value>({ namespace: Namespaces.SESSION, key });

			expect(result).toEqual(value);
		});

		it('should return null for a missing key', async () => {
			const result = await cacheService.get({ namespace: Namespaces.AUTH_CODE, key: randomUUID() });

			expect(result).toBeNull();
		});

		it('should respect TTL and expire value', async () => {
			const key = randomUUID();

			await cacheService.set({ namespace: Namespaces.AUTH_CODE, key, value: 'expires', ttl: 100 });

			await new Promise((resolve) => setTimeout(resolve, 200));

			const result = await cacheService.get({ namespace: Namespaces.AUTH_CODE, key });
			expect(result).toBeNull();
		});

		it('should read from master with STRONG consistency level', async () => {
			const key = randomUUID();
			const value = 'strong-read';

			await cacheService.set({ namespace: Namespaces.AUTH_CODE, key, value });
			const result = await cacheService.get<string>({
				namespace: Namespaces.AUTH_CODE,
				key,
				consistencyLevel: ConsistencyLevel.STRONG,
			});

			expect(result).toBe(value);
		});
	});

	describe('has', () => {
		it('should return true for an existing key', async () => {
			const key = randomUUID();

			await cacheService.set({ namespace: Namespaces.AUTH_CODE, key, value: 'exists' });
			const result = await cacheService.has({ namespace: Namespaces.AUTH_CODE, key });

			expect(result).toBe(true);
		});

		it('should return false for a missing key', async () => {
			const result = await cacheService.has({ namespace: Namespaces.AUTH_CODE, key: randomUUID() });

			expect(result).toBe(false);
		});
	});

	describe('deleteOne', () => {
		it('should delete an existing key', async () => {
			const key = randomUUID();

			await cacheService.set({ namespace: Namespaces.AUTH_CODE, key, value: 'to-delete' });
			await cacheService.deleteOne({ namespace: Namespaces.AUTH_CODE, key });

			const result = await cacheService.get({ namespace: Namespaces.AUTH_CODE, key });
			expect(result).toBeNull();
		});

		it('should return true even for a non-existent key', async () => {
			const result = await cacheService.deleteOne({
				namespace: Namespaces.AUTH_CODE,
				key: randomUUID(),
			});

			expect(result).toBe(true);
		});
	});

	describe('deleteAll', () => {
		it('should clear all cached values', async () => {
			const key1 = randomUUID();
			const key2 = randomUUID();

			await cacheService.set({ namespace: Namespaces.AUTH_CODE, key: key1, value: 'val1' });
			await cacheService.set({ namespace: Namespaces.SESSION, key: key2, value: 'val2' });

			await cacheService.deleteAll({ namespace: Namespaces.AUTH_CODE });

			const result1 = await cacheService.get({ namespace: Namespaces.AUTH_CODE, key: key1 });
			const result2 = await cacheService.get({ namespace: Namespaces.SESSION, key: key2 });

			expect(result1).toBeNull();
			expect(result2).toBeNull();
		});
	});

	describe('incrementByOne', () => {
		it('should increment a counter', async () => {
			const key = randomUUID();
			const namespacedKey = `${Namespaces.AUTH_CODE}:${key}`;

			await cacheService.incrementByOne({ namespace: Namespaces.AUTH_CODE, key });
			await cacheService.incrementByOne({ namespace: Namespaces.AUTH_CODE, key });
			await cacheService.incrementByOne({ namespace: Namespaces.AUTH_CODE, key });

			const value = await redis.get(namespacedKey);
			expect(value).toBe('3');
		});
	});

	describe('withLock', () => {
		it('should execute operation under a distributed lock', async () => {
			const lockKey = `test-lock:${randomUUID()}`;
			let executed = false;

			await cacheService.withLock({
				lockKey,
				operation: async () => {
					executed = true;
					return 'result';
				},
			});

			expect(executed).toBe(true);
		});

		it('should return the operation result', async () => {
			const lockKey = `test-lock:${randomUUID()}`;
			const expected = { data: randomUUID() };

			const result = await cacheService.withLock({
				lockKey,
				operation: async () => expected,
			});

			expect(result).toEqual(expected);
		});

		it('should release lock after operation completes', async () => {
			const lockKey = `test-lock:${randomUUID()}`;

			await cacheService.withLock({
				lockKey,
				operation: async () => 'done',
			});

			const second = await cacheService.withLock({
				lockKey,
				operation: async () => 'second',
			});

			expect(second).toBe('second');
		});
	});

	describe('acquireLock and releaseLock', () => {
		it('should acquire and release a lock manually', async () => {
			const lockKey = `manual-lock:${randomUUID()}`;

			const lock = await cacheService.acquireLock({ lockKey, ttl: 5000 });
			expect(lock).toBeDefined();

			await expect(cacheService.releaseLock({ lock })).resolves.not.toThrow();
		});
	});

	describe('Redis clients', () => {
		it('write client should be connected', async () => {
			const result = await redis.ping();
			expect(result).toBe('PONG');
		});
	});
});

